// ============================================================
// Build the dashboard payload from Jobber data (workflow static
// data). Produces MONTHLY (top-level, backward compatible) AND
// WEEKLY views so the dashboard can toggle Month / Week.
// ============================================================
const sd = $getWorkflowStaticData('global');

function dedupe(arr, idKey) {
  const seen = new Set();
  const out = [];
  for (const x of (arr || [])) {
    const k = x && x[idKey];
    if (k == null) { out.push(x); continue; }
    if (seen.has(k)) continue;
    seen.add(k); out.push(x);
  }
  return out;
}

const quotes = dedupe(sd.qAll || [], 'id');
const requests = dedupe(sd.rAll || [], 'id');
const clients = dedupe(sd.cAll || [], 'id');
const invoices = dedupe(sd.iAll || [], 'id');

const now = new Date();
const year = now.getFullYear();
const MONTH_NAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const months = MONTH_NAMES.slice(0, now.getMonth() + 1);

// Vancouver-local Y/M/D for a date string.
function vparts(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return null;
  const p = new Intl.DateTimeFormat('en-US', { timeZone: 'America/Vancouver', year: 'numeric', month: 'numeric', day: 'numeric' }).formatToParts(d);
  return { y: Number(p.find(x => x.type === 'year').value), m: Number(p.find(x => x.type === 'month').value), d: Number(p.find(x => x.type === 'day').value) };
}

// MONTH label (current year only).
function monthOf(dateStr) {
  const p = vparts(dateStr);
  if (!p || p.y !== year) return null;
  return MONTH_NAMES[p.m - 1];
}

// WEEK helpers — weeks start Monday; label = that Monday's "MMM D".
function dayNum(y, m, d) { return Math.floor(Date.UTC(y, m - 1, d) / 86400000); }
function mondayDn(y, m, d) {
  const dow = new Date(Date.UTC(y, m - 1, d)).getUTCDay(); // 0=Sun..6=Sat
  const off = dow === 0 ? 6 : dow - 1;
  return dayNum(y, m, d) - off;
}
function labelOfDn(dn) {
  const dt = new Date(dn * 86400000);
  return MONTH_NAMES[dt.getUTCMonth()] + ' ' + dt.getUTCDate();
}
function weekOf(dateStr) {
  const p = vparts(dateStr);
  if (!p || p.y !== year) return null;
  return labelOfDn(mondayDn(p.y, p.m, p.d));
}
// Ordered week labels from Jan 1's week through this week.
const startDn = mondayDn(year, 1, 1);
const tp = vparts(now.toISOString());
const endDn = mondayDn(tp.y, tp.m, tp.d);
const weeks = [];
for (let dn = startDn; dn <= endDn; dn += 7) weeks.push(labelOfDn(dn));

function personOf(quote) {
  return (quote.salesperson && quote.salesperson.name && quote.salesperson.name.full || '').trim() || 'Unassigned';
}

// Compute the full metric block for a period scheme (month or week).
function buildView(labelOf, labels) {
  const has = {};
  labels.forEach(l => { has[l] = true; });
  function empty() { const o = {}; labels.forEach(l => { o[l] = 0; }); return o; }
  function ensure(obj, p) { if (!obj[p]) obj[p] = empty(); return obj[p]; }

  const revenueProduced = empty();
  for (const inv of invoices) { const k = labelOf(inv.issuedDate); if (k && has[k]) { const a = inv.amounts || {}; revenueProduced[k] += (parseFloat(a.total) || 0) - (parseFloat(a.invoiceBalance) || 0); } }

  const cashCollected = empty();

  const newLeads = empty();
  for (const c of clients) { const k = labelOf(c.createdAt); if (k && has[k]) newLeads[k] += 1; }

  const newRequests = empty();
  for (const r of requests) { const k = labelOf(r.createdAt); if (k && has[k]) newRequests[k] += 1; }

  const quotesSentTotal = empty();
  const quotesSentByPerson = {};
  const quotesConvertedTotal = empty();
  const quotesConvertedByPerson = {};
  const convertedDollarsTotal = empty();
  const convertedDollarsByPerson = {};

  for (const q of quotes) {
    const status = (q.quoteStatus || '').toUpperCase();
    const person = personOf(q);
    const amount = parseFloat(q.amounts && q.amounts.total) || 0;
    const sk = labelOf(q.sentAt);
    if (sk && has[sk]) { quotesSentTotal[sk] += 1; ensure(quotesSentByPerson, person)[sk] += 1; }
    if (status === 'CONVERTED') {
      const ck = labelOf(q.transitionedAt);
      if (ck && has[ck]) {
        quotesConvertedTotal[ck] += 1;
        ensure(quotesConvertedByPerson, person)[ck] += 1;
        convertedDollarsTotal[ck] += amount;
        ensure(convertedDollarsByPerson, person)[ck] += amount;
      }
    }
  }

  function round2(map) { for (const k of Object.keys(map)) map[k] = Math.round(map[k] * 100) / 100; return map; }
  round2(revenueProduced); round2(cashCollected); round2(convertedDollarsTotal);

  const allPersons = Array.from(new Set(Object.keys(quotesSentByPerson).concat(Object.keys(quotesConvertedByPerson))));
  for (const p of allPersons) { ensure(quotesSentByPerson, p); ensure(quotesConvertedByPerson, p); ensure(convertedDollarsByPerson, p); }
  for (const p of allPersons) round2(convertedDollarsByPerson[p]);

  function rate(conv, sent) { const o = {}; for (const k of labels) o[k] = (sent[k] || 0) > 0 ? Math.round((conv[k] / sent[k]) * 1000) / 10 : 0; return o; }
  const conversionRateTotal = rate(quotesConvertedTotal, quotesSentTotal);
  const conversionRateByPerson = {};
  for (const p of allPersons) conversionRateByPerson[p] = rate(quotesConvertedByPerson[p], quotesSentByPerson[p]);

  function avg(dollars, conv) { const o = {}; for (const k of labels) o[k] = (conv[k] || 0) > 0 ? Math.round((dollars[k] / conv[k]) * 100) / 100 : 0; return o; }
  const avgSaleTotal = avg(convertedDollarsTotal, quotesConvertedTotal);
  const avgSaleByPerson = {};
  for (const p of allPersons) avgSaleByPerson[p] = avg(convertedDollarsByPerson[p], quotesConvertedByPerson[p]);

  return {
    revenueProduced, cashCollected, newLeads, newRequests,
    quotesSent: { total: quotesSentTotal, byPerson: quotesSentByPerson },
    quotesConverted: { total: quotesConvertedTotal, byPerson: quotesConvertedByPerson },
    conversionRate: { total: conversionRateTotal, byPerson: conversionRateByPerson },
    convertedDollars: { total: convertedDollarsTotal, byPerson: convertedDollarsByPerson },
    avgSale: { total: avgSaleTotal, byPerson: avgSaleByPerson }
  };
}

const monthly = buildView(monthOf, months);
const weekly = buildView(weekOf, weeks);

return [Object.assign({
  months, weeks, weekly,
  _debug: { quotes: quotes.length, requests: requests.length, clients: clients.length, invoices: invoices.length, weeks: weeks.length }
}, monthly)];
